const RECEIVER_URL = "http://127.0.0.1:8787/auth/refresh";
const TARGET_DOMAIN = "undermind.ai";

chrome.runtime.onInstalled.addListener(() => {
  chrome.storage.local.get("companionToken", (data) => {
    if (!data.companionToken) {
      chrome.action.openPopup();
    }
  });
  chrome.alarms.create("syncCookies", { periodInMinutes: 10 });
});

chrome.alarms.onAlarm.addListener((alarm) => {
  if (alarm.name === "syncCookies") {
    syncCookies();
  }
});

chrome.cookies.onChanged.addListener((changeInfo) => {
  if (changeInfo.cookie.domain.includes(TARGET_DOMAIN)) {
    syncCookies();
  }
});

async function syncCookies() {
  const data = await chrome.storage.local.get("companionToken");
  const token = data.companionToken;
  if (!token) {
    chrome.action.setBadgeText({ text: "!" });
    chrome.action.setBadgeBackgroundColor({ color: "#FF0000" });
    return;
  }

  try {
    const cookies = await chrome.cookies.getAll({ domain: TARGET_DOMAIN });

    // Filter out analytics cookies
    const validCookies = cookies.filter(c => 
      !c.name.startsWith("_ga") && 
      !c.name.startsWith("ph_") &&
      !c.name.includes("posthog")
    );

    const cookieHeader = validCookies.map(c => `${c.name}=${c.value}`).join("; ");
    const csrfCookie = validCookies.find(c => c.name === "csrftoken" || c.name === "app-csrftoken");
    const csrftoken = csrfCookie ? csrfCookie.value : "";

    if (!cookieHeader || !csrftoken) {
      console.log("Missing essential cookies. Wait for user to log in.");
      chrome.action.setBadgeText({ text: "?" });
      chrome.action.setBadgeBackgroundColor({ color: "#FFA500" });
      return;
    }

    const payload = {
      cookie: cookieHeader,
      csrftoken: csrftoken,
      user_agent: navigator.userAgent,
      origin: "https://app.undermind.ai"
    };

    const response = await fetch(RECEIVER_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Companion-Token": token
      },
      body: JSON.stringify(payload)
    });

    if (response.ok) {
      chrome.action.setBadgeText({ text: "✓" });
      chrome.action.setBadgeBackgroundColor({ color: "#00FF00" });
    } else {
      chrome.action.setBadgeText({ text: "!" });
      chrome.action.setBadgeBackgroundColor({ color: "#FF0000" });
    }
  } catch (error) {
    console.error("Error syncing cookies:", error);
    chrome.action.setBadgeText({ text: "X" });
    chrome.action.setBadgeBackgroundColor({ color: "#FF0000" });
  }
}

