const RECEIVER_URL = "http://127.0.0.1:8787";

document.addEventListener("DOMContentLoaded", async () => {
  const data = await chrome.storage.local.get("companionToken");
  if (data.companionToken) {
    showView("status-view");
    checkStatus(data.companionToken);
  } else {
    showView("setup-view");
  }

  document.getElementById("save-token").addEventListener("click", async () => {
    const token = document.getElementById("token-input").value.trim();
    if (!token) return;

    // Verify token by pinging /auth/status
    try {
      const response = await fetch(`${RECEIVER_URL}/auth/status`, {
        headers: { "X-Companion-Token": token }
      });
      if (response.ok) {
        await chrome.storage.local.set({ companionToken: token });
        showView("status-view");
        checkStatus(token);
        // Force an immediate sync
        chrome.runtime.sendMessage({ action: "syncCookies" });
      } else {
        showError("Invalid token or MCP server is not running.");
      }
    } catch (e) {
      showError("Could not reach MCP server. Is `undermind-mcp serve` running?");
    }
  });

  document.getElementById("refresh-now").addEventListener("click", async () => {
    // We can just call syncCookies in background by triggering the alarm or sending a message.
    // Easiest is to send a message to background script.
    // Wait, the background script doesn't listen to messages, so let's just do it directly or add a listener.
    // Since we didn't add a listener in background.js, we can add it, or just let background.js run it via alarm.
    // For now, let's just ping the background to sync.
    // Wait, we need to modify background.js to listen to messages, or we can just fetch here.
    // To keep it simple, we can just do the fetch here as well.
    const token = (await chrome.storage.local.get("companionToken")).companionToken;
    try {
      const cookies = await chrome.cookies.getAll({ domain: "undermind.ai" });
      const validCookies = cookies.filter(c => 
        !c.name.startsWith("_ga") && 
        !c.name.startsWith("ph_") &&
        !c.name.includes("posthog")
      );

      const cookieHeader = validCookies.map(c => `${c.name}=${c.value}`).join("; ");
      const csrfCookie = validCookies.find(c => c.name === "csrftoken" || c.name === "app-csrftoken");
      const csrftoken = csrfCookie ? csrfCookie.value : "";

      const payload = {
        cookie: cookieHeader,
        csrftoken: csrftoken,
        user_agent: navigator.userAgent,
        origin: "https://app.undermind.ai"
      };

      const response = await fetch(`${RECEIVER_URL}/auth/refresh`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Companion-Token": token
        },
        body: JSON.stringify(payload)
      });
      if (response.ok) {
        checkStatus(token);
      }
    } catch (e) {
      console.error(e);
    }
  });

  document.getElementById("disconnect").addEventListener("click", async () => {
    const data = await chrome.storage.local.get("companionToken");
    if (data.companionToken) {
      try {
        await fetch(`${RECEIVER_URL}/auth/clear`, {
          method: "POST",
          headers: { "X-Companion-Token": data.companionToken }
        });
      } catch (e) {}
    }
    await chrome.storage.local.remove("companionToken");
    showView("setup-view");
  });
});

async function checkStatus(token) {
  try {
    const response = await fetch(`${RECEIVER_URL}/auth/status`, {
      headers: { "X-Companion-Token": token }
    });
    const data = await response.json();

    const dot = document.getElementById("status-dot");
    const text = document.getElementById("status-text");

    if (data.connected) {
      dot.className = "dot green";
      text.textContent = "Connected";
      document.getElementById("session-age").textContent = `${Math.round(data.age_seconds / 60)} minutes`;
      document.getElementById("bundle-hash").textContent = data.bundle_hash || "unknown";
    } else {
      dot.className = "dot orange";
      text.textContent = "No session. Please log in to Undermind.";
      document.getElementById("session-age").textContent = "-";
      document.getElementById("bundle-hash").textContent = "-";
    }
  } catch (e) {
    const dot = document.getElementById("status-dot");
    const text = document.getElementById("status-text");
    dot.className = "dot red";
    text.textContent = "Cannot reach MCP server";
  }
}

function showView(id) {
  document.querySelectorAll(".view").forEach(v => v.classList.add("hidden"));
  document.getElementById(id).classList.remove("hidden");
}

function showError(msg) {
  const el = document.getElementById("setup-error");
  el.textContent = msg;
  el.classList.remove("hidden");
}

