"""CLI entry point for undermind-mcp.

Subcommands:
    serve   — Run the MCP stdio server + local HTTP receiver.
    init    — First-run setup: ToS acknowledgment, companion token generation.
    doctor  — Diagnostics: session status, bundle hash, connectivity.
    reset   — Clear all stored credentials and tokens.

Example:
    $ undermind-mcp serve
    $ undermind-mcp init --use-keychain
    $ undermind-mcp doctor
    $ undermind-mcp reset
"""

from __future__ import annotations

import argparse
import sys


def _cmd_serve(args: argparse.Namespace) -> None:
    """Run the MCP stdio server + local HTTP receiver."""
    from undermind_mcp.server import serve
    serve()


def _cmd_init(args: argparse.Namespace) -> None:
    """First-run setup: ToS notice, companion token, config files."""
    print("undermind-mcp reuses your browser session to interact with Undermind.")
    print("This may violate Undermind's Terms of Service.")
    print("This tool is for personal, single-user use only.")
    print()
    response = input("Type 'I understand' to proceed: ")
    if response.strip().lower() != "i understand":
        print("Aborted.")
        sys.exit(1)

    from undermind_mcp.http_receiver import generate_companion_token
    token = generate_companion_token()
    print("\nCompanion token generated and saved.")
    print(f"Token: {token}\n")
    print("Please install the companion extension and paste this token in its popup.")

    # Optionally configure keychain if requested.
    use_keychain: bool = args.use_keychain
    if use_keychain:
        print("Keychain persistence will be enabled on next launch (if configured).")


def _cmd_doctor(args: argparse.Namespace) -> None:
    """Diagnostics: ping /auth/status, list projects, check bundle hash."""
    import asyncio

    from undermind_mcp.auth_store import AuthStore
    from undermind_mcp.client import UndermindClient
    from undermind_mcp.logging_conf import configure_logging
    from undermind_mcp.rate_limit import RateLimiter

    configure_logging(level="ERROR")
    store = AuthStore()

    if not store.is_fresh():
        print("Session is missing or expired. Please use the companion extension to log in.")
        return

    print("Session is valid.")

    async def run():
        rl = RateLimiter(global_capacity=10.0, global_refill_rate=1.0, named_buckets={})
        client = UndermindClient(store, rl)
        try:
            projects = await client.list_projects()
            print(f"Successfully connected to Undermind. Found {len(projects)} projects.")
        except Exception as e:
            print(f"Error connecting to Undermind: {e}")

    asyncio.run(run())


def _cmd_reset(args: argparse.Namespace) -> None:
    """Clear auth_store, keychain entry, companion token, cached runs."""
    import asyncio

    from undermind_mcp.auth_store import AuthStore
    from undermind_mcp.http_receiver import _TOKEN_FILE

    store = AuthStore()
    asyncio.run(store.clear())

    if _TOKEN_FILE.exists():
        _TOKEN_FILE.unlink()

    print("Reset complete: credentials and companion token cleared.")


def build_parser() -> argparse.ArgumentParser:
    """Build the CLI argument parser.

    Example:
        >>> parser = build_parser()
        >>> args = parser.parse_args(["serve"])
        >>> args.func  # doctest: +ELLIPSIS
        <function _cmd_serve at ...>
    """
    parser = argparse.ArgumentParser(
        prog="undermind-mcp",
        description="Local MCP server for driving Undermind via authenticated browser session.",
    )
    subparsers = parser.add_subparsers(dest="command", help="Available commands")

    # serve
    serve_parser = subparsers.add_parser("serve", help="Run MCP server + HTTP receiver")
    serve_parser.set_defaults(func=_cmd_serve)

    # init
    init_parser = subparsers.add_parser("init", help="First-run setup")
    init_parser.add_argument(
        "--use-keychain",
        action="store_true",
        default=False,
        help="Persist session to OS keychain (may trigger GUI prompt on macOS)",
    )
    init_parser.set_defaults(func=_cmd_init)

    # doctor
    doctor_parser = subparsers.add_parser("doctor", help="Run diagnostics")
    doctor_parser.set_defaults(func=_cmd_doctor)

    # reset
    reset_parser = subparsers.add_parser("reset", help="Clear all stored data")
    reset_parser.set_defaults(func=_cmd_reset)

    return parser


def main() -> None:
    """CLI entry point.

    Example:
        $ undermind-mcp --help
    """
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    args.func(args)


if __name__ == "__main__":
    main()

