    k = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", k)
    return [x.lower() for x in re.split(r"[^A-Za-z0-9]+", k) if x]


def key_sensitive(k: str) -> bool:
    norm = re.sub(r"[_\-\s]", "", k.lower())
    if _WHOLE_KEY.match(norm):          # whole key: code/state/key/apikey/csrftoken/...
