    return any(seg in STRONG_SEG for seg in _segs(k))  # strong segments only


def redact_obj(o: Any) -> Any:
    if isinstance(o, list):
        return [redact_obj(x) for x in cast("list[Any]", o)]
    if isinstance(o, dict):
        return {
            k: ("<REDACTED>" if key_sensitive(k) else redact_obj(v))
            for k, v in cast("dict[Any, Any]", o).items()
