    return redact_str(o)


def scan_for_secrets(blob: str) -> list[str]:
    """Gate: return non-empty list of offending fragments if any secret survives redaction.
    Reuses the same patterns; UUIDs and '<REDACTED>' are not leaks."""
    leaks: list[str] = []
